Resource: aws_lb.main
File: /alb.tf: 45-66
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-networking-policies/ensure-that-alb-drops-http-headers

		45 | resource "aws_lb" "main" {
		46 |   name               = "${var.project}-${var.environment}-alb"
		47 |   internal           = false
		48 |   load_balancer_type = "application"
		49 |   security_groups    = [aws_security_group.alb.id]
		50 |   subnets            = aws_subnet.public[*].id
		51 | 
		52 |   enable_deletion_protection = true
		53 | 
		54 |   dynamic "access_logs" {
		55 |     for_each = var.alb_access_logs_bucket != "" ? [1] : []
		56 |     content {
		57 |       bucket  = var.alb_access_logs_bucket
		58 |       prefix  = "${var.project}/${var.environment}/alb"
		59 |       enabled = true
		60 |     }
		61 |   }
		62 | 
		63 |   tags = {
		64 |     Name = "${var.project}-${var.environment}-alb"
		65 |   }
		66 | }

