Resource: aws_iam_policy_document.ecs_logs_kms
File: /ecs.tf: 4-37
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-iam-policies/bc-aws-356

		4  | data "aws_iam_policy_document" "ecs_logs_kms" {
		5  |   statement {
		6  |     sid     = "RootAccess"
		7  |     effect  = "Allow"
		8  |     actions = ["kms:*"]
		9  |     principals {
		10 |       type        = "AWS"
		11 |       identifiers = ["arn:${data.aws_partition.current.partition}:iam::${data.aws_caller_identity.current.account_id}:root"]
		12 |     }
		13 |     resources = ["*"]
		14 |   }
		15 | 
		16 |   statement {
		17 |     sid    = "AllowCloudWatchLogs"
		18 |     effect = "Allow"
		19 |     actions = [
		20 |       "kms:Encrypt*",
		21 |       "kms:Decrypt*",
		22 |       "kms:ReEncrypt*",
		23 |       "kms:GenerateDataKey*",
		24 |       "kms:Describe*",
		25 |     ]
		26 |     principals {
		27 |       type        = "Service"
		28 |       identifiers = ["logs.${var.aws_region}.amazonaws.com"]
		29 |     }
		30 |     resources = ["*"]
		31 |     condition {
		32 |       test     = "ArnLike"
		33 |       variable = "kms:EncryptionContext:aws:logs:arn"
		34 |       values   = ["arn:${data.aws_partition.current.partition}:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:*"]
		35 |     }
		36 |   }
		37 | }

