Resource: aws_iam_policy_document.frontend_kms
File: /frontend.tf: 23-51
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-iam-policies/bc-aws-356

		23 | data "aws_iam_policy_document" "frontend_kms" {
		24 |   statement {
		25 |     sid    = "EnableRootAccess"
		26 |     effect = "Allow"
		27 |     principals {
		28 |       type        = "AWS"
		29 |       identifiers = ["arn:${data.aws_partition.current.partition}:iam::${data.aws_caller_identity.current.account_id}:root"]
		30 |     }
		31 |     actions   = ["kms:*"]
		32 |     resources = ["*"]
		33 |   }
		34 | 
		35 |   # CloudFront OAC necesita Decrypt/GenerateDataKey para servir objetos SSE-KMS.
		36 |   statement {
		37 |     sid    = "AllowCloudFrontOAC"
		38 |     effect = "Allow"
		39 |     principals {
		40 |       type        = "Service"
		41 |       identifiers = ["cloudfront.amazonaws.com"]
		42 |     }
		43 |     actions   = ["kms:Decrypt", "kms:GenerateDataKey"]
		44 |     resources = ["*"]
		45 |     condition {
		46 |       test     = "StringEquals"
		47 |       variable = "aws:SourceArn"
		48 |       values   = [aws_cloudfront_distribution.main.arn]
		49 |     }
		50 |   }
		51 | }

